module parallel2serial(
    input clk, 
    input rst_n, 
    input [3:0] d,
    output reg valid_out, 
    output reg dout
);
    reg [2:0] cnt;
    reg [3:0] data;
    reg valid;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 3'd0;
            data <= 4'd0;
            valid <= 1'b0;
        end else begin
            if (cnt == 3'd3) begin
                data <= d;
                cnt <= 3'd0;
                valid <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                valid <= 1'b0;
                data <= {data[2:0], data[3]};
            end
        end
    end

    assign dout = data[3];
    assign valid_out = valid;
endmodule
